export function getMondayBasedWeekdayIndex(date) {
    return (date.getDay() + 6) % 7;
}
export function isSameMonth(first, second) {
    return first.getFullYear() === second.getFullYear() && first.getMonth() === second.getMonth();
}
export function getDayCellIndexForDate(dayCells, date) {
    return dayCells.findIndex((cell) => isSameDay(cell.date, date));
}
export function isSameDay(first, second) {
    return (first.getFullYear() === second.getFullYear() &&
        first.getMonth() === second.getMonth() &&
        first.getDate() === second.getDate());
}
export function areSameRange(a, b) {
    return !!a[0] && !!a[1] && !!b[0] && !!b[1] && isSameDay(a[0], b[0]) && isSameDay(a[1], b[1]);
}
export function normalizeDate(date) {
    date.setHours(0, 0, 0, 0);
    return date;
}
